import { describe, it, expect } from "bun:test"

import type { ModelsResponse } from "~/services/copilot/get-models"

import { resolveEndpoint } from "./endpoint-routing"

function mockModels(
  entries: Array<{ id: string; supported_endpoints: Array<string> }>,
): ModelsResponse {
  return {
    object: "list",
    data: entries.map((e) => ({
      id: e.id,
      name: e.id,
      version: "1.0",
      supported_endpoints: e.supported_endpoints,
      object: "model" as const,
      created: 0,
      owned_by: "test",
    })),
  } as unknown as ModelsResponse
}

describe("resolveEndpoint", () => {
  const models = mockModels([
    {
      id: "claude-sonnet-4.6",
      supported_endpoints: ["/v1/messages", "/chat/completions"],
    },
    {
      id: "claude-opus-4.6",
      supported_endpoints: ["/v1/messages"],
    },
    {
      id: "gpt-5.5",
      supported_endpoints: ["/responses", "/chat/completions"],
    },
    {
      id: "gpt-4.1",
      supported_endpoints: ["/chat/completions"],
    },
    {
      id: "gemini-2.5-pro",
      supported_endpoints: ["/chat/completions"],
    },
  ])

  it("routes Claude models to /v1/messages", () => {
    expect(resolveEndpoint("claude-sonnet-4.6", models)).toBe("/v1/messages")
    expect(resolveEndpoint("claude-opus-4.6", models)).toBe("/v1/messages")
  })

  it("routes GPT-5.x to /responses when available", () => {
    expect(resolveEndpoint("gpt-5.5", models)).toBe("/responses")
  })

  it("routes GPT-4.x to /chat/completions", () => {
    expect(resolveEndpoint("gpt-4.1", models)).toBe("/chat/completions")
  })

  it("routes Gemini to /chat/completions", () => {
    expect(resolveEndpoint("gemini-2.5-pro", models)).toBe("/chat/completions")
  })

  it("falls back to /chat/completions for unknown models", () => {
    expect(resolveEndpoint("unknown-model", models)).toBe("/chat/completions")
  })

  it("falls back to /chat/completions when no cached models", () => {
    expect(resolveEndpoint("claude-sonnet-4.6")).toBe("/chat/completions")
    expect(resolveEndpoint("claude-sonnet-4.6", undefined)).toBe(
      "/chat/completions",
    )
  })

  it("prefers /v1/messages over /chat/completions for Claude", () => {
    // claude-sonnet-4.6 has both endpoints — should pick /v1/messages
    expect(resolveEndpoint("claude-sonnet-4.6", models)).toBe("/v1/messages")
  })

  it("prefers /responses over /chat/completions for dual-endpoint models", () => {
    // gpt-5.5 has both /responses and /chat/completions
    expect(resolveEndpoint("gpt-5.5", models)).toBe("/responses")
  })
})

import { describe, expect, it, beforeEach } from "bun:test"

import {
  anthropicToCopilotModelId,
  copilotToAnthropicModelId,
} from "./model-mapping"
import { state } from "./state"

// Helper to set up model catalog
function setCatalog(ids: Array<string>) {
  state.models = {
    object: "list",
    data: ids.map((id) => ({
      id,
      object: "model",
      created: 0,
      owned_by: "anthropic",
    })),
  } as unknown as typeof state.models
}

describe("anthropicToCopilotModelId", () => {
  beforeEach(() => {
    setCatalog(["claude-opus-4.6", "claude-opus-4.6-1m"])
  })

  it("maps dash format to dot format", () => {
    expect(anthropicToCopilotModelId("claude-opus-4-6", false)).toBe(
      "claude-opus-4.6",
    )
    expect(anthropicToCopilotModelId("claude-sonnet-4-6", false)).toBe(
      "claude-sonnet-4.6",
    )
    expect(anthropicToCopilotModelId("claude-opus-4-5", false)).toBe(
      "claude-opus-4.5",
    )
    expect(anthropicToCopilotModelId("claude-opus-4-7", false)).toBe(
      "claude-opus-4.7",
    )
  })

  it("handles [1m] suffix when model exists in catalog", () => {
    expect(anthropicToCopilotModelId("claude-opus-4-6[1m]", false)).toBe(
      "claude-opus-4.6-1m",
    )
  })

  it("strips [1m] suffix when model not in catalog", () => {
    expect(anthropicToCopilotModelId("claude-sonnet-4-6[1m]", false)).toBe(
      "claude-sonnet-4.6",
    )
  })

  it("passes through unknown models unchanged", () => {
    expect(anthropicToCopilotModelId("gpt-4o", false)).toBe("gpt-4o")
  })

  it("handles haiku models", () => {
    expect(anthropicToCopilotModelId("claude-haiku-4-5", false)).toBe(
      "claude-haiku-4.5",
    )
  })

  // ── -internal suffix resolution ──

  it("resolves to -1m-internal when only that variant exists", () => {
    setCatalog(["claude-opus-4.7", "claude-opus-4.7-1m-internal"])
    expect(anthropicToCopilotModelId("claude-opus-4.7", true)).toBe(
      "claude-opus-4.7-1m-internal",
    )
    expect(anthropicToCopilotModelId("claude-opus-4.7[1m]", false)).toBe(
      "claude-opus-4.7-1m-internal",
    )
  })

  it("prefers -1m over -1m-internal when both exist", () => {
    setCatalog([
      "claude-opus-4.8",
      "claude-opus-4.8-1m",
      "claude-opus-4.8-1m-internal",
    ])
    expect(anthropicToCopilotModelId("claude-opus-4.8", true)).toBe(
      "claude-opus-4.8-1m",
    )
  })

  // ── Effort suffix handling ──

  it("maps -high suffix through dash→dot conversion", () => {
    setCatalog(["claude-opus-4.7", "claude-opus-4.7-high"])
    expect(anthropicToCopilotModelId("claude-opus-4-7-high", false)).toBe(
      "claude-opus-4.7-high",
    )
  })

  it("maps -xhigh suffix through dash→dot conversion", () => {
    setCatalog(["claude-opus-4.7", "claude-opus-4.7-xhigh"])
    expect(anthropicToCopilotModelId("claude-opus-4-7-xhigh", false)).toBe(
      "claude-opus-4.7-xhigh",
    )
  })

  it("falls back to base when effort variant not in catalog", () => {
    setCatalog(["claude-opus-4.7"])
    expect(anthropicToCopilotModelId("claude-opus-4-7-high", false)).toBe(
      "claude-opus-4.7",
    )
  })
})

describe("copilotToAnthropicModelId", () => {
  it("maps dot format to dash format", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.6")).toBe("claude-opus-4-6")
    expect(copilotToAnthropicModelId("claude-opus-4.7")).toBe("claude-opus-4-7")
  })

  it("handles -1m suffix → [1m]", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.6-1m")).toBe(
      "claude-opus-4-6[1m]",
    )
  })

  it("passes through unknown models unchanged", () => {
    expect(copilotToAnthropicModelId("gpt-4o")).toBe("gpt-4o")
  })

  // ── -internal suffix stripping ──

  it("strips -internal and maps -1m to [1m]", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.7-1m-internal")).toBe(
      "claude-opus-4-7[1m]",
    )
  })

  it("strips -internal from non-1m models", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.7-internal")).toBe(
      "claude-opus-4-7",
    )
  })

  // ── Effort suffix preservation ──

  it("preserves -high suffix so client gets the right model back", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.7-high")).toBe(
      "claude-opus-4-7-high",
    )
  })

  it("preserves -xhigh suffix", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.7-xhigh")).toBe(
      "claude-opus-4-7-xhigh",
    )
  })

  // ── Combined suffix scenarios ──

  it("handles -1m + -internal correctly (strip order matters)", () => {
    // This was the bug: endsWith("-1m") failed because it ended with "-1m-internal"
    // Must strip -internal FIRST, then check -1m
    const result = copilotToAnthropicModelId("claude-opus-4.7-1m-internal")
    expect(result).toBe("claude-opus-4-7[1m]")
    // Verify it doesn't produce "claude-opus-4-7-1m" (is1M=false bug)
    expect(result).not.toBe("claude-opus-4-7-1m")
    expect(result).not.toContain("-1m-")
  })

  // ── Full effort routing table ──
  // These test the reverse mapping that clients see in response.model

  it("response model table: base model", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.7")).toBe("claude-opus-4-7")
  })

  it("response model table: effort=high variant", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.7-high")).toBe(
      "claude-opus-4-7-high",
    )
  })

  it("response model table: effort=xhigh variant", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.7-xhigh")).toBe(
      "claude-opus-4-7-xhigh",
    )
  })

  it("response model table: 1m-internal variant", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.7-1m-internal")).toBe(
      "claude-opus-4-7[1m]",
    )
  })

  it("response model table: 4.6 base", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.6")).toBe("claude-opus-4-6")
  })

  it("response model table: 4.6-1m", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.6-1m")).toBe(
      "claude-opus-4-6[1m]",
    )
  })

  // ── Non-Claude models should pass through ──

  it("GPT models pass through unchanged", () => {
    expect(copilotToAnthropicModelId("gpt-5.5")).toBe("gpt-5.5")
    expect(copilotToAnthropicModelId("gpt-5.5-2026-04-23")).toBe(
      "gpt-5.5-2026-04-23",
    )
  })

  it("Gemini models pass through unchanged", () => {
    expect(copilotToAnthropicModelId("gemini-2.5-pro")).toBe("gemini-2.5-pro")
  })
})

import { state } from "./state"

// Forward map: Anthropic dash format → Copilot dot format
const MODEL_ID_MAP: Record<string, string> = {
  "claude-opus-4-7": "claude-opus-4.7",
  "claude-opus-4-6": "claude-opus-4.6",
  "claude-opus-4-5": "claude-opus-4.5",
  "claude-sonnet-4-6": "claude-sonnet-4.6",
  "claude-sonnet-4-5": "claude-sonnet-4.5",
  "claude-sonnet-4": "claude-sonnet-4",
  "claude-opus-4": "claude-opus-4",
  "claude-haiku-4-5": "claude-haiku-4.5",
}

/** Suffixes that encode effort level — stripped before mapping, re-appended after */
const EFFORT_SUFFIXES = ["-xhigh", "-high"] as const

// Reverse map: Copilot dot format → Anthropic dash format
const REVERSE_MODEL_ID_MAP: Record<string, string> = Object.fromEntries(
  Object.entries(MODEL_ID_MAP).map(([k, v]) => [v, k]),
)

/**
 * Convert an Anthropic-style model ID to a Copilot-style model ID.
 * Strips date suffixes, converts dashes to dots, and appends -1m if needed.
 * Only appends -1m if the model actually has a 1M variant in the cached models.
 */
export function anthropicToCopilotModelId(
  model: string,
  is1M: boolean,
): string {
  let base = model

  // Strip [1m] suffix if present (Claude Code sends this)
  const has1MSuffix = base.endsWith("[1m]")
  if (has1MSuffix) {
    base = base.slice(0, -4)
  }

  // Strip effort suffixes (-high, -xhigh) — re-appended after mapping
  let effortSuffix = ""
  for (const suffix of EFFORT_SUFFIXES) {
    if (base.endsWith(suffix)) {
      effortSuffix = suffix
      base = base.slice(0, -suffix.length)
      break
    }
  }

  // Strip date suffixes (e.g. claude-sonnet-4-20250514 → claude-sonnet-4)
  if (/^claude-sonnet-4-\d{8}/.test(base)) {
    base = "claude-sonnet-4"
  } else if (/^claude-opus-4-\d{8}/.test(base)) {
    base = "claude-opus-4"
  }

  const mapped = MODEL_ID_MAP[base] ?? base

  // Re-append effort suffix — check catalog first
  if (effortSuffix) {
    const candidate = `${mapped}${effortSuffix}`
    if (state.models?.data.some((m) => m.id === candidate)) {
      return candidate
    }
  }

  const use1M = is1M || has1MSuffix

  // Only append -1m if the 1M variant actually exists in the model catalog
  if (use1M) {
    const candidate = `${mapped}-1m`
    const exists = state.models?.data.some((m) => m.id === candidate)
    if (exists) return candidate

    // Try -1m-internal (transient preview suffix, will be dropped when model graduates)
    const internalCandidate = `${mapped}-1m-internal`
    const internalExists = state.models?.data.some(
      (m) => m.id === internalCandidate,
    )
    if (internalExists) return internalCandidate
  }

  return mapped
}

/**
 * Convert a Copilot-style model ID back to Anthropic-style.
 * Converts dots to dashes and maps -1m back to [1m].
 * Preserves effort suffixes (-high, -xhigh) so the client can
 * send the same model back for consistent behavior.
 */
export function copilotToAnthropicModelId(copilotModel: string): string {
  let base = copilotModel

  // Strip suffixes in the correct order: -internal first, then -1m, then effort
  // because model IDs are structured as: base[-1m[-internal]][-high|-xhigh]
  // Example: claude-opus-4.7-1m-internal → strip -internal → strip -1m → base

  // 1. Strip -internal (transient preview suffix)
  const hasInternal = base.endsWith("-internal")
  if (hasInternal) base = base.slice(0, -9)

  // 2. Strip effort suffixes — preserve for re-append
  let effortSuffix = ""
  for (const suffix of EFFORT_SUFFIXES) {
    if (base.endsWith(suffix)) {
      effortSuffix = suffix
      base = base.slice(0, -suffix.length)
      break
    }
  }

  // 3. Strip -1m
  const is1M = base.endsWith("-1m")
  if (is1M) base = base.slice(0, -3)

  const mapped = REVERSE_MODEL_ID_MAP[base] ?? base
  const result = is1M ? `${mapped}[1m]` : mapped

  // Re-append effort suffix so the client gets the right model back
  return effortSuffix ? `${result}${effortSuffix}` : result
}

// Anthropic API Types

export interface AnthropicMessagesPayload {
  model: string
  messages: Array<AnthropicMessage>
  max_tokens: number
  system?: string | Array<AnthropicTextBlock>
  metadata?: {
    user_id?: string
  }
  stop_sequences?: Array<string>
  stream?: boolean
  temperature?: number
  top_p?: number
  top_k?: number
  tools?: Array<AnthropicTool>
  tool_choice?: {
    type: "auto" | "any" | "tool" | "none"
    name?: string
  }
  thinking?: {
    type: "enabled" | "disabled" | "adaptive"
    budget_tokens?: number
  }
  service_tier?: "auto" | "standard_only"
  output_config?: {
    effort?: "low" | "medium" | "high" | "max"
    [key: string]: unknown
  }
}

export interface AnthropicTextBlock {
  type: "text"
  text: string
}

export interface AnthropicImageBlock {
  type: "image"
  source: {
    type: "base64"
    media_type: "image/jpeg" | "image/png" | "image/gif" | "image/webp"
    data: string
  }
}

export interface AnthropicToolResultBlock {
  type: "tool_result"
  tool_use_id: string
  content: string
  is_error?: boolean
}

export interface AnthropicToolUseBlock {
  type: "tool_use"
  id: string
  name: string
  input: Record<string, unknown>
}

export interface AnthropicThinkingBlock {
  type: "thinking"
  thinking: string
}

export type AnthropicUserContentBlock =
  | AnthropicTextBlock
  | AnthropicImageBlock
  | AnthropicToolResultBlock

export type AnthropicAssistantContentBlock =
  | AnthropicTextBlock
  | AnthropicToolUseBlock
  | AnthropicThinkingBlock

export interface AnthropicUserMessage {
  role: "user"
  content: string | Array<AnthropicUserContentBlock>
}

export interface AnthropicAssistantMessage {
  role: "assistant"
  content: string | Array<AnthropicAssistantContentBlock>
}

export type AnthropicMessage = AnthropicUserMessage | AnthropicAssistantMessage

export interface AnthropicTool {
  name: string
  description?: string
  input_schema: Record<string, unknown>
}

export interface AnthropicResponse {
  id: string
  type: "message"
  role: "assistant"
  content: Array<AnthropicAssistantContentBlock>
  model: string
  stop_reason:
    | "end_turn"
    | "max_tokens"
    | "stop_sequence"
    | "tool_use"
    | "pause_turn"
    | "refusal"
    | null
  stop_sequence: string | null
  usage: {
    input_tokens: number
    output_tokens: number
    cache_creation_input_tokens?: number
    cache_read_input_tokens?: number
    service_tier?: "standard" | "priority" | "batch"
  }
}

export type AnthropicResponseContentBlock = AnthropicAssistantContentBlock

// Anthropic Stream Event Types
export interface AnthropicMessageStartEvent {
  type: "message_start"
  message: Omit<
    AnthropicResponse,
    "content" | "stop_reason" | "stop_sequence"
  > & {
    content: []
    stop_reason: null
    stop_sequence: null
  }
}

export interface AnthropicContentBlockStartEvent {
  type: "content_block_start"
  index: number
  content_block:
    | { type: "text"; text: string }
    | (Omit<AnthropicToolUseBlock, "input"> & {
        input: Record<string, unknown>
      })
    | { type: "thinking"; thinking: string }
}

export interface AnthropicContentBlockDeltaEvent {
  type: "content_block_delta"
  index: number
  delta:
    | { type: "text_delta"; text: string }
    | { type: "input_json_delta"; partial_json: string }
    | { type: "thinking_delta"; thinking: string }
    | { type: "signature_delta"; signature: string }
}

export interface AnthropicContentBlockStopEvent {
  type: "content_block_stop"
  index: number
}

export interface AnthropicMessageDeltaEvent {
  type: "message_delta"
  delta: {
    stop_reason?: AnthropicResponse["stop_reason"]
    stop_sequence?: string | null
  }
  usage?: {
    input_tokens?: number
    output_tokens: number
    cache_creation_input_tokens?: number
    cache_read_input_tokens?: number
  }
}

export interface AnthropicMessageStopEvent {
  type: "message_stop"
}

export interface AnthropicPingEvent {
  type: "ping"
}

export interface AnthropicErrorEvent {
  type: "error"
  error: {
    type: string
    message: string
  }
}

export type AnthropicStreamEventData =
  | AnthropicMessageStartEvent
  | AnthropicContentBlockStartEvent
  | AnthropicContentBlockDeltaEvent
  | AnthropicContentBlockStopEvent
  | AnthropicMessageDeltaEvent
  | AnthropicMessageStopEvent
  | AnthropicPingEvent
  | AnthropicErrorEvent

// State for streaming translation
export interface AnthropicStreamState {
  messageStartSent: boolean
  contentBlockIndex: number
  contentBlockOpen: boolean
  toolCalls: {
    [openAIToolIndex: number]: {
      id: string
      name: string
      anthropicBlockIndex: number
    }
  }
}

import type { Context } from "hono"

import consola from "consola"
import { streamSSE } from "hono/streaming"

import { awaitApproval } from "~/lib/approval"
import { resolveEndpoint } from "~/lib/endpoint-routing"
import { anthropicToCopilotModelId } from "~/lib/model-mapping"
import { checkRateLimit } from "~/lib/rate-limit"
import { state } from "~/lib/state"
import {
  createChatCompletions,
  type ChatCompletionChunk,
  type ChatCompletionResponse,
} from "~/services/copilot/create-chat-completions"
import {
  createResponses,
  createResponsesStreamState,
  translateResponsesStreamEvent,
} from "~/services/copilot/create-responses"
import {
  forwardNativeMessagesNonStreaming,
  forwardNativeMessagesStreaming,
} from "~/services/copilot/forward-native-messages"

import {
  type AnthropicMessagesPayload,
  type AnthropicStreamState,
} from "./anthropic-types"
import {
  translateToAnthropic,
  translateToOpenAI,
} from "./non-stream-translation"
import { translateChunkToAnthropicEvents } from "./stream-translation"

const CONTEXT_1M_BETA = "context-1m-2025-08-07"

/**
 * Check if the request wants 1M context via the anthropic-beta header.
 * The Claude Agent SDK sets `anthropic-beta: context-1m-2025-08-07`
 * instead of appending [1m] to the model name.
 */
function detectWants1M(c: Context): boolean {
  const betaHeader = c.req.header("anthropic-beta") ?? ""
  return betaHeader.split(",").some((s) => s.trim() === CONTEXT_1M_BETA)
}

export async function handleCompletion(c: Context) {
  await checkRateLimit(state)

  const anthropicPayload = await c.req.json<AnthropicMessagesPayload>()
  consola.debug("Anthropic request payload:", JSON.stringify(anthropicPayload))

  if (state.manualApprove) {
    await awaitApproval()
  }

  // Check per-request 1M context: anthropic-beta header or global flag
  const wants1M = detectWants1M(c) || state.is1MContext

  const copilotModelId = anthropicToCopilotModelId(
    anthropicPayload.model,
    wants1M,
  )
  const endpoint = resolveEndpoint(copilotModelId, state.models)

  // Native Anthropic passthrough for Claude models
  if (endpoint === "/v1/messages") {
    consola.debug(`Using native /v1/messages passthrough for ${copilotModelId}`)
    return handleNativePassthrough(c, anthropicPayload, wants1M)
  }

  // Translate Anthropic → OpenAI format for non-Claude models
  const openAIPayload = translateToOpenAI(anthropicPayload)
  consola.debug(
    "Translated OpenAI request payload:",
    JSON.stringify(openAIPayload),
  )

  // /responses for GPT-5.x models (responses-only or preferred)
  if (endpoint === "/responses") {
    consola.debug(`Using /responses endpoint for ${copilotModelId}`)
    return handleResponsesViaAnthropic(c, openAIPayload)
  }

  // /chat/completions for legacy models
  const response = await createChatCompletions(openAIPayload)

  if (isNonStreaming(response)) {
    consola.debug(
      "Non-streaming response from Copilot:",
      JSON.stringify(response).slice(-400),
    )
    const anthropicResponse = translateToAnthropic(response)
    consola.debug(
      "Translated Anthropic response:",
      JSON.stringify(anthropicResponse),
    )
    return c.json(anthropicResponse)
  }

  consola.debug("Streaming response from Copilot")
  return streamSSE(c, async (stream) => {
    const streamState: AnthropicStreamState = {
      messageStartSent: false,
      contentBlockIndex: 0,
      contentBlockOpen: false,
      toolCalls: {},
    }

    for await (const rawEvent of response) {
      consola.debug("Copilot raw stream event:", JSON.stringify(rawEvent))
      if (rawEvent.data === "[DONE]") {
        break
      }

      if (!rawEvent.data) {
        continue
      }

      const chunk = JSON.parse(rawEvent.data) as ChatCompletionChunk
      const events = translateChunkToAnthropicEvents(chunk, streamState)

      for (const event of events) {
        consola.debug("Translated Anthropic event:", JSON.stringify(event))
        await stream.writeSSE({
          event: event.type,
          data: JSON.stringify(event),
        })
      }
    }
  })
}

async function handleNativePassthrough(
  c: Context,
  payload: AnthropicMessagesPayload,
  is1M: boolean,
) {
  if (!payload.stream) {
    const response = await forwardNativeMessagesNonStreaming(payload, is1M)
    return c.json(response)
  }

  return streamSSE(c, async (stream) => {
    for await (const event of forwardNativeMessagesStreaming(payload, is1M)) {
      await stream.writeSSE({
        event: event.type,
        data: JSON.stringify(event.data),
      })
    }
  })
}

const isNonStreaming = (
  response: Awaited<ReturnType<typeof createChatCompletions>>,
): response is ChatCompletionResponse => Object.hasOwn(response, "choices")

/**
 * Handle a request that needs the /responses endpoint but arrived via /v1/messages.
 * Flow: Anthropic payload → already translated to OpenAI → /responses → OpenAI response → Anthropic format.
 */
async function handleResponsesViaAnthropic(
  c: Context,
  openAIPayload: Parameters<typeof createResponses>[0],
) {
  const response = await createResponses(openAIPayload)

  if (isNonStreaming(response)) {
    const anthropicResponse = translateToAnthropic(response)
    return c.json(anthropicResponse)
  }

  return streamSSE(c, async (stream) => {
    const responsesState = createResponsesStreamState()
    const anthropicState: AnthropicStreamState = {
      messageStartSent: false,
      contentBlockIndex: 0,
      contentBlockOpen: false,
      toolCalls: {},
    }

    for await (const rawEvent of response) {
      if (!rawEvent.data || rawEvent.data === "[DONE]") continue

      const parsed = JSON.parse(rawEvent.data) as Record<string, unknown>
      const eventType =
        rawEvent.event ?? (parsed.type as string | undefined) ?? ""

      // Responses SSE → OpenAI chunks
      const chunks = translateResponsesStreamEvent(
        { event: eventType, data: parsed },
        responsesState,
      )

      // OpenAI chunks → Anthropic SSE events
      for (const chunk of chunks) {
        const events = translateChunkToAnthropicEvents(chunk, anthropicState)
        for (const event of events) {
          await stream.writeSSE({
            event: event.type,
            data: JSON.stringify(event),
          })
        }
      }
    }
  })
}

import {
  anthropicToCopilotModelId,
  copilotToAnthropicModelId,
} from "~/lib/model-mapping"
import { state } from "~/lib/state"
import {
  type ChatCompletionResponse,
  type ChatCompletionsPayload,
  type ContentPart,
  type Message,
  type TextPart,
  type Tool,
  type ToolCall,
} from "~/services/copilot/create-chat-completions"

import {
  type AnthropicAssistantContentBlock,
  type AnthropicAssistantMessage,
  type AnthropicMessage,
  type AnthropicMessagesPayload,
  type AnthropicResponse,
  type AnthropicTextBlock,
  type AnthropicThinkingBlock,
  type AnthropicTool,
  type AnthropicToolResultBlock,
  type AnthropicToolUseBlock,
  type AnthropicUserContentBlock,
  type AnthropicUserMessage,
} from "./anthropic-types"
import { mapOpenAIStopReasonToAnthropic } from "./utils"

// Payload translation

export function translateToOpenAI(
  payload: AnthropicMessagesPayload,
): ChatCompletionsPayload {
  return {
    model: translateModelName(payload.model),
    messages: translateAnthropicMessagesToOpenAI(
      payload.messages,
      payload.system,
    ),
    max_tokens: payload.max_tokens,
    stop: payload.stop_sequences,
    stream: payload.stream,
    temperature: payload.temperature,
    top_p: payload.top_p,
    user: payload.metadata?.user_id,
    tools: translateAnthropicToolsToOpenAI(payload.tools),
    tool_choice: translateAnthropicToolChoiceToOpenAI(payload.tool_choice),
  }
}

function translateModelName(model: string): string {
  return anthropicToCopilotModelId(model, state.is1MContext)
}

function translateAnthropicMessagesToOpenAI(
  anthropicMessages: Array<AnthropicMessage>,
  system: string | Array<AnthropicTextBlock> | undefined,
): Array<Message> {
  const systemMessages = handleSystemPrompt(system)

  const otherMessages = anthropicMessages.flatMap((message) =>
    message.role === "user" ?
      handleUserMessage(message)
    : handleAssistantMessage(message),
  )

  return [...systemMessages, ...otherMessages]
}

function handleSystemPrompt(
  system: string | Array<AnthropicTextBlock> | undefined,
): Array<Message> {
  if (!system) {
    return []
  }

  if (typeof system === "string") {
    return [{ role: "system", content: system }]
  } else {
    const systemText = system.map((block) => block.text).join("\n\n")
    return [{ role: "system", content: systemText }]
  }
}

function handleUserMessage(message: AnthropicUserMessage): Array<Message> {
  const newMessages: Array<Message> = []

  if (Array.isArray(message.content)) {
    const toolResultBlocks = message.content.filter(
      (block): block is AnthropicToolResultBlock =>
        block.type === "tool_result",
    )
    const otherBlocks = message.content.filter(
      (block) => block.type !== "tool_result",
    )

    // Tool results must come first to maintain protocol: tool_use -> tool_result -> user
    for (const block of toolResultBlocks) {
      newMessages.push({
        role: "tool",
        tool_call_id: block.tool_use_id,
        content: mapContent(block.content),
      })
    }

    if (otherBlocks.length > 0) {
      newMessages.push({
        role: "user",
        content: mapContent(otherBlocks),
      })
    }
  } else {
    newMessages.push({
      role: "user",
      content: mapContent(message.content),
    })
  }

  return newMessages
}

function handleAssistantMessage(
  message: AnthropicAssistantMessage,
): Array<Message> {
  if (!Array.isArray(message.content)) {
    return [
      {
        role: "assistant",
        content: mapContent(message.content),
      },
    ]
  }

  const toolUseBlocks = message.content.filter(
    (block): block is AnthropicToolUseBlock => block.type === "tool_use",
  )

  const textBlocks = message.content.filter(
    (block): block is AnthropicTextBlock => block.type === "text",
  )

  const thinkingBlocks = message.content.filter(
    (block): block is AnthropicThinkingBlock => block.type === "thinking",
  )

  // Combine text and thinking blocks, as OpenAI doesn't have separate thinking blocks
  const allTextContent = [
    ...textBlocks.map((b) => b.text),
    ...thinkingBlocks.map((b) => b.thinking),
  ].join("\n\n")

  return toolUseBlocks.length > 0 ?
      [
        {
          role: "assistant",
          content: allTextContent || null,
          tool_calls: toolUseBlocks.map((toolUse) => ({
            id: toolUse.id,
            type: "function",
            function: {
              name: toolUse.name,
              arguments: JSON.stringify(toolUse.input),
            },
          })),
        },
      ]
    : [
        {
          role: "assistant",
          content: mapContent(message.content),
        },
      ]
}

function mapContent(
  content:
    | string
    | Array<AnthropicUserContentBlock | AnthropicAssistantContentBlock>,
): string | Array<ContentPart> | null {
  if (typeof content === "string") {
    return content
  }
  if (!Array.isArray(content)) {
    return null
  }

  const hasImage = content.some((block) => block.type === "image")
  if (!hasImage) {
    return content
      .filter(
        (block): block is AnthropicTextBlock | AnthropicThinkingBlock =>
          block.type === "text" || block.type === "thinking",
      )
      .map((block) => (block.type === "text" ? block.text : block.thinking))
      .join("\n\n")
  }

  const contentParts: Array<ContentPart> = []
  for (const block of content) {
    switch (block.type) {
      case "text": {
        contentParts.push({ type: "text", text: block.text })

        break
      }
      case "thinking": {
        contentParts.push({ type: "text", text: block.thinking })

        break
      }
      case "image": {
        contentParts.push({
          type: "image_url",
          image_url: {
            url: `data:${block.source.media_type};base64,${block.source.data}`,
          },
        })

        break
      }
      // No default
    }
  }
  return contentParts
}

function translateAnthropicToolsToOpenAI(
  anthropicTools: Array<AnthropicTool> | undefined,
): Array<Tool> | undefined {
  if (!anthropicTools) {
    return undefined
  }
  return anthropicTools.map((tool) => ({
    type: "function",
    function: {
      name: tool.name,
      description: tool.description,
      parameters: tool.input_schema,
    },
  }))
}

function translateAnthropicToolChoiceToOpenAI(
  anthropicToolChoice: AnthropicMessagesPayload["tool_choice"],
): ChatCompletionsPayload["tool_choice"] {
  if (!anthropicToolChoice) {
    return undefined
  }

  switch (anthropicToolChoice.type) {
    case "auto": {
      return "auto"
    }
    case "any": {
      return "required"
    }
    case "tool": {
      if (anthropicToolChoice.name) {
        return {
          type: "function",
          function: { name: anthropicToolChoice.name },
        }
      }
      return undefined
    }
    case "none": {
      return "none"
    }
    default: {
      return undefined
    }
  }
}

// Response translation

function getThinkingBlocks(
  reasoningText: string | null | undefined,
): Array<AnthropicThinkingBlock> {
  if (!reasoningText) return []
  return [{ type: "thinking", thinking: reasoningText }]
}

export function translateToAnthropic(
  response: ChatCompletionResponse,
): AnthropicResponse {
  // Merge content from all choices
  const allTextBlocks: Array<AnthropicTextBlock> = []
  const allToolUseBlocks: Array<AnthropicToolUseBlock> = []
  const allThinkingBlocks: Array<AnthropicThinkingBlock> = []
  let stopReason: "stop" | "length" | "tool_calls" | "content_filter" | null =
    null // default
  stopReason = response.choices[0]?.finish_reason ?? stopReason

  // Process all choices to extract text and tool use blocks
  for (const choice of response.choices) {
    const textBlocks = getAnthropicTextBlocks(choice.message.content)
    const toolUseBlocks = getAnthropicToolUseBlocks(choice.message.tool_calls)

    // Map reasoning_text from GPT-5.x /responses to Anthropic thinking blocks
    allThinkingBlocks.push(...getThinkingBlocks(choice.message.reasoning_text))

    allTextBlocks.push(...textBlocks)
    allToolUseBlocks.push(...toolUseBlocks)

    // Use the finish_reason from the first choice, or prioritize tool_calls
    if (choice.finish_reason === "tool_calls" || stopReason === "stop") {
      stopReason = choice.finish_reason
    }
  }

  return {
    id: response.id,
    type: "message",
    role: "assistant",
    model: copilotToAnthropicModelId(response.model),
    content: [...allThinkingBlocks, ...allTextBlocks, ...allToolUseBlocks],
    stop_reason: mapOpenAIStopReasonToAnthropic(stopReason),
    stop_sequence: null,
    usage: {
      input_tokens:
        (response.usage?.prompt_tokens ?? 0)
        - (response.usage?.prompt_tokens_details?.cached_tokens ?? 0),
      output_tokens: response.usage?.completion_tokens ?? 0,
      ...(response.usage?.prompt_tokens_details?.cached_tokens
        !== undefined && {
        cache_read_input_tokens:
          response.usage.prompt_tokens_details.cached_tokens,
      }),
    },
  }
}

function getAnthropicTextBlocks(
  messageContent: Message["content"],
): Array<AnthropicTextBlock> {
  if (typeof messageContent === "string") {
    return [{ type: "text", text: messageContent }]
  }

  if (Array.isArray(messageContent)) {
    return messageContent
      .filter((part): part is TextPart => part.type === "text")
      .map((part) => ({ type: "text", text: part.text }))
  }

  return []
}

function getAnthropicToolUseBlocks(
  toolCalls: Array<ToolCall> | undefined,
): Array<AnthropicToolUseBlock> {
  if (!toolCalls) {
    return []
  }
  return toolCalls.map((toolCall) => ({
    type: "tool_use",
    id: toolCall.id,
    name: toolCall.function.name,
    input: JSON.parse(toolCall.function.arguments) as Record<string, unknown>,
  }))
}

import consola from "consola"
import { events } from "fetch-event-stream"

import { copilotHeaders, copilotBaseUrl } from "~/lib/api-config"
import { HTTPError } from "~/lib/error"
import { state } from "~/lib/state"

export const createChatCompletions = async (
  payload: ChatCompletionsPayload,
) => {
  if (!state.copilotToken) throw new Error("Copilot token not found")

  const enableVision = payload.messages.some(
    (x) =>
      typeof x.content !== "string"
      && x.content?.some((x) => x.type === "image_url"),
  )

  // Agent/user check for X-Initiator header
  // Determine if any message is from an agent ("assistant" or "tool")
  const isAgentCall = payload.messages.some((msg) =>
    ["assistant", "tool"].includes(msg.role),
  )

  // Build headers and add X-Initiator
  const headers: Record<string, string> = {
    ...copilotHeaders(state, enableVision),
    "X-Initiator": isAgentCall ? "agent" : "user",
  }

  const response = await fetch(`${copilotBaseUrl(state)}/chat/completions`, {
    method: "POST",
    headers,
    body: JSON.stringify(payload),
  })

  if (!response.ok) {
    consola.error("Failed to create chat completions", response)
    throw new HTTPError("Failed to create chat completions", response)
  }

  if (payload.stream) {
    return events(response)
  }

  return (await response.json()) as ChatCompletionResponse
}

